noncompliant:
// Noncompliant: lowercase start
enum someEnumeration {
    VALUE1,
    VALUE2
};

// Noncompliant: snake_case naming
enum color_type {
    RED,
    GREEN,
    BLUE
};

// Noncompliant: all lowercase
enum status {
    ACTIVE,
    INACTIVE
};

compliant:
// Compliant: PascalCase naming
enum SomeEnumeration {
    VALUE1,
    VALUE2
};

// Compliant: starts with capital letter
enum ColorType {
    RED,
    GREEN,
    BLUE
};

// Compliant: proper naming convention
enum Status {
    ACTIVE,
    INACTIVE
};

// Compliant: scoped enum with proper naming
enum class FileMode {
    READ,
    WRITE,
    APPEND
};
